-- ============================================================================
-- sutaz.ca — Lead seed (210 source rows → deduplicated to unique leads)
-- ============================================================================
-- Source: Canada_210_Real_Verified_Leads.xlsx (210 rows).
-- Data-quality fix vs the blueprint: the source contains known duplicates
-- (e.g., "Azuro Digital (Toronto Regional Account)" appears at rows 0, 30, 60
-- with identical province/city/industry/company/domain/scope). The blueprint
-- seeded all 210 then DELETE-d duplicates on production — sloppy.
--
-- This seed loads the 210 rows into a TEMP staging table, then INSERTs only
-- DISTINCT (province, city, industry, company_name, website_domain,
-- automation_scope) rows into `leads`. No DELETE on the live table.
-- ============================================================================

-- Temporary staging table — dropped automatically at session end.
CREATE TEMP TABLE _leads_stage (
  province        canadian_province,
  city            TEXT,
  industry        industry_category,
  company_name    TEXT,
  website_domain  TEXT,
  automation_scope automation_pitch
);

