-- ============================================================================
-- Deduplicated insert: only unique rows reach the production leads table.
-- ============================================================================
INSERT INTO leads (province, city, industry, company_name, website_domain, automation_scope, source)
SELECT DISTINCT ON (province, city, industry, company_name, website_domain, automation_scope)
       province, city, industry, company_name, website_domain, automation_scope, 'seed'
FROM _leads_stage
ORDER BY province, city, industry, company_name, website_domain, automation_scope;

-- Reporting (informational — surfaces how many duplicates were removed)
DO $$
DECLARE
  staged INT;
  loaded INT;
BEGIN
  SELECT count(*) INTO staged FROM _leads_stage;
  SELECT count(*) INTO loaded FROM leads WHERE source = 'seed';
  RAISE NOTICE 'Seed: % source rows staged, % unique leads loaded (% duplicates removed).',
    staged, loaded, staged - loaded;
END $$;
